#include <bits/stdc++.h>
using namespace std;
int main(){
    long long n,tr[35][35];
    cin>>n;
    for(int i=1;i<=n;i++){
        for(int j=1;j<=i;j++){
            if(j==1 || j==i)tr[i][j]=1;
            else tr[i][j]=tr[i-1][j-1]+tr[i-1][j];
            cout<<tr[i][j]<<' ';
        }
        cout<<endl;
    }
    return 0;
}
